namespace DocSummary.Models;

public class SummarizeRequest
{
    public required string DocumentText { get; set; }
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
}

namespace DocSummary.Services;

public interface IDocumentSummarizer
{
    string Summarize(string documentText);
}

namespace DocSummary.Services;

/// <summary>
/// Extractive summarizer that selects the most important sentences from the document.
/// </summary>
public class ExtractiveSummarizer : IDocumentSummarizer
{
    private const int MaxSummarySentences = 3;

    public string Summarize(string documentText)
    {
        if (string.IsNullOrWhiteSpace(documentText))
            return string.Empty;

        var sentences = SplitIntoSentences(documentText);

        if (sentences.Length <= MaxSummarySentences)
            return string.Join(" ", sentences);

        var scored = sentences
            .Select((sentence, index) => new { Sentence = sentence, Score = ScoreSentence(sentence, index, sentences) })
            .OrderByDescending(s => s.Score)
            .Take(MaxSummarySentences)
            .OrderBy(s => Array.IndexOf(sentences, s.Sentence))
            .Select(s => s.Sentence);

        return string.Join(" ", scored);
    }

    private static string[] SplitIntoSentences(string text)
    {
        return text.Split(['. ', '! ', '? '], StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                   .Where(s => s.Length > 0)
                   .Select(s => s.TrimEnd('.', '!', '?') + ".")
                   .ToArray();
    }

    private static double ScoreSentence(string sentence, int index, string[] allSentences)
    {
        var words = sentence.Split(' ', StringSplitOptions.RemoveEmptyEntries);
        double lengthScore = Math.Min(words.Length / 20.0, 1.0);

        // Favor earlier sentences (positional bias)
        double positionScore = 1.0 / (index + 1);

        // Word frequency scoring
        var allWords = allSentences.SelectMany(s => s.Split(' ', StringSplitOptions.RemoveEmptyEntries))
                                   .Select(w => w.ToLowerInvariant())
                                   .GroupBy(w => w)
                                   .ToDictionary(g => g.Key, g => g.Count());

        double frequencyScore = words.Sum(w => allWords.GetValueOrDefault(w.ToLowerInvariant())) / (double)words.Length;

        return lengthScore + positionScore * 2 + frequencyScore;
    }
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly IDocumentSummarizer _summarizer;

    public SummarizeController(IDocumentSummarizer summarizer)
    {
        _summarizer = summarizer;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.DocumentText))
            return BadRequest("DocumentText must not be empty.");

        var summary = _summarizer.Summarize(request.DocumentText);

        return Ok(new SummarizeResponse { Summary = summary });
    }
}

